mapper.update:
UPDATE tbl_board
SET likecnt = likecnt + #{amount}
WHERE bno = #{bno}

UPDATE tbl_board
SET dislikecnt = dislikecnt +
#{amount}
WHERE bno = #{bno}

mapper.select:
SELECT * FROM ( SELECT /*+ INDEX_DESC(b pk_board) */ rownum rn, b.bno, b.title, b.content, b.writer, b.regdate, b.updatedate, b.cat_id, c.cat_name, m.user_img, b.viewcnt, b.replycnt, b.likecnt FROM tbl_board b LEFT JOIN tbl_category c ON b.cat_id = c.cat_id LEFT JOIN tbl_member m ON b.writer = m.userid
1=1
AND b.cat_id = #{category}
AND b.cat_id LIKE '1%' AND b.cat_id LIKE '2%' AND b.cat_id LIKE '3%' AND b.cat_id LIKE '4%' AND b.cat_id LIKE '5%' AND b.cat_id LIKE '6%' AND b.cat_id LIKE '7%' AND b.cat_id LIKE '8%'
AND rownum <= #{cri.pageEnd}
) WHERE rn > #{cri.pageStart}

SELECT * FROM ( SELECT b.bno, b.title, b.content, b.writer, b.regdate, b.replycnt, b.likecnt, b.dislikecnt, c.cat_name, c.cat_slug, c.cat_id, c.parent_id AS group_id, NVL(p.cat_name, c.cat_name) AS group_name FROM tbl_board b LEFT JOIN tbl_category c ON b.cat_id = c.cat_id LEFT JOIN tbl_category p ON c.parent_id = p.cat_id
AND c.cat_name = #{category}
ORDER BY b.bno DESC ) WHERE ROWNUM <= 20
